// Hand-written SSRF policy e2e tests.
// These are NOT generated by alef — edit this file directly.
//
// TODO(ssrf-parity): Once CrawlConfig.ssrf is annotated with alef(skip),
// add a fixture at fixtures/validation/validation_ssrf_loopback_denied.json
// and run `task alef:generate` to replace this file with alef-generated output.

import { describe, expect, it } from "vitest";
import { scrape, createEngine } from "@kreuzberg/kreuzcrawl";

// Port 9 (discard) is deliberately chosen: SSRF policy rejects the URL
// before any TCP connection attempt, so the test does not depend on
// a listening server.
const LOOPBACK_URL = "http://127.0.0.1:9/";
const PRIVATE_URL = "http://10.0.0.1:9/";

describe("ssrf", () => {
	it("ssrf_loopback_denied_by_default: default config rejects loopback URLs before any network connect", async () => {
		await expect(async () => {
			const engine = createEngine(null);
			await scrape(engine, LOOPBACK_URL);
		}).rejects.toThrow(/ssrf_policy_violation/);
	}, 30000);

	it("ssrf_private_network_class_a_denied: default config rejects RFC-1918 class-A addresses", async () => {
		await expect(async () => {
			const engine = createEngine(null);
			await scrape(engine, PRIVATE_URL);
		}).rejects.toThrow(/ssrf_policy_violation/);
	}, 30000);
});
